function renderYamlEditor(host, key, originalYaml, onSave = null, opts = {}) {
  const readOnly = !!opts.readOnly;
  host._initYamlEdit(key, originalYaml);
  const current = readOnly
    ? originalYaml
    : (host._editedYaml[key] ?? originalYaml);
  const isDirty = !readOnly && current !== originalYaml;
  const saving = !!host._savingYaml[key];
  return x`
    <ha-code-editor
      mode="yaml"
      .value=${current}
      ?read-only=${readOnly}
      @value-changed=${(e5) => {
        if (readOnly) return;
        host._onYamlInput(key, e5.detail.value);
      }}
      autocomplete-entities
      style="--code-mirror-font-size:12px;${readOnly ? "opacity:0.95;" : ""}"
    ></ha-code-editor>
    ${
      isDirty || (onSave && !readOnly)
        ? x`
          <div class="yaml-edit-bar">
            ${
              isDirty
                ? x`
                  <span class="yaml-unsaved">
                    <ha-icon
                      icon="mdi:circle-edit-outline"
                      style="--mdc-icon-size:13px;"
                    ></ha-icon>
                    ${host._t("chat_yaml_unsaved_changes", "Unsaved changes")}
                  </span>
                `
                : x`<span style="flex:1;"></span>`
            }
            ${
              onSave
                ? x`
                  <button
                    class="btn btn-primary"
                    ?disabled=${saving || !isDirty}
                    @click=${() => onSave(key)}
                  >
                    <ha-icon
                      icon="mdi:content-save"
                      style="--mdc-icon-size:13px;"
                    ></ha-icon>
                    ${saving ? host._t("chat_yaml_saving", "Saving\u2026") : host._t("chat_yaml_save_changes", "Save changes")}
                  </button>
                `
                : ""
            }
          </div>
        `
        : ""
    }
  `;
}

// src/shared/formatting.js
function humanizeToken(value) {
  if (value == null || value === "") return "";
  return String(value)
    .replace(/_/g, " ")
    .replace(/\b\w/g, (c3) => c3.toUpperCase());
}
function fmtEntity(hass, id) {
  if (!id) return "";
  const eid = String(id);
  const stateObj = hass?.states?.[eid];
  if (stateObj?.attributes?.friendly_name)
    return stateObj.attributes.friendly_name;
  const parts = eid.split(".");
  const raw = (parts.length > 1 ? parts.slice(1).join(".") : parts[0]).replace(
    /_/g,
    " ",
  );
  return raw.replace(/\b\w/g, (c3) => c3.toUpperCase());
}
var _LIST_CONNECTORS = {
  en: { last: " and ", oxford: ", and " },
  fr: { last: " et ", oxford: " et " },
  de: { last: " und ", oxford: " und " },
  es: { last: " y ", oxford: " y " },
  it: { last: " e ", oxford: " e " },
  nl: { last: " en ", oxford: " en " },
  hu: { last: " \xE9s ", oxford: " \xE9s " },
};
function _langKey2(language, table) {
  const base = String(language || "en")
    .toLowerCase()
    .split("-")[0];
  return table[base] ? base : "en";
}
function fmtEntities(hass, val, language) {
  if (!val) return "";
  const arr = Array.isArray(val) ? val : [val];
  if (arr.length === 1) return fmtEntity(hass, arr[0]);
  const c3 = _LIST_CONNECTORS[_langKey2(language, _LIST_CONNECTORS)];
  if (arr.length === 2)
    return `${fmtEntity(hass, arr[0])}${c3.last}${fmtEntity(hass, arr[1])}`;
  return (
    arr
      .slice(0, -1)
      .map((e5) => fmtEntity(hass, e5))
      .join(", ") +
    c3.oxford +
    fmtEntity(hass, arr[arr.length - 1])
  );
}
